INSERT INTO `wp_posts` VALUES (7,1,'2026-03-04 10:25:38','2026-03-04 09:25:38','<!-- wp:group {\"metadata\":{\"categories\":[\"header\"],\"patternName\":\"core/cabecera-de-ancho-completo-con-imagen-principal\",\"name\":\"Cabecera de ancho completo con imagen principal\"},\"align\":\"full\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull\"><!-- wp:cover {\"url\":\"http://ishield-2.local/wp-content/uploads/2026/02/stock-photo-cybersecurity-shield-activation.webp\",\"id\":24,\"dimRatio\":0,\"overlayColor\":\"black\",\"isUserOverlayColor\":true,\"minHeight\":40,\"minHeightUnit\":\"vw\",\"contentPosition\":\"center center\",\"sizeSlug\":\"full\",\"align\":\"full\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\"}},\"color\":{\"duotone\":[\"rgb(100, 20, 20)\",\"rgb(135, 135, 135)\"]}}} -->\n<div class=\"wp-block-cover alignfull\" style=\"margin-top:0;min-height:40vw\"><img class=\"wp-block-cover__image-background wp-image-24 size-full\" alt=\"\" src=\"http://ishield-2.local/wp-content/uploads/2026/02/stock-photo-cybersecurity-shield-activation.webp\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-black-background-color has-background-dim-0 has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"color\":{\"text\":\"#b42e2e\"},\"elements\":{\"link\":{\"color\":{\"text\":\"#b42e2e\"}}}},\"fontSize\":\"x-large\"} -->\n<p class=\"has-text-align-center has-text-color has-link-color has-x-large-font-size\" style=\"color:#b42e2e\"><mark style=\"background-color:rgba(0, 0, 0, 0)\" class=\"has-inline-color has-base-color\"><strong><em>Protegemos tu empresa de ciberataques las 24h</em></strong></mark></p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:cover --></div>\n<!-- /wp:group -->\n\n<!-- wp:separator {\"metadata\":{\"blockVisibility\":false}} -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:html -->\n<style>\n    .ishield-hero-section {\n        font-family: \'Montserrat\', sans-serif;\n        color: #333;\n        max-width: 1100px;\n        margin: 0 auto;\n        padding: 40px 20px;\n        box-sizing: border-box;\n    }\n\n    /* Introducción centrada */\n    .ishield-intro-text {\n        text-align: center;\n        font-size: 1.15em;\n        color: #555;\n        line-height: 1.6;\n        margin-bottom: 60px;\n        max-width: 800px;\n        margin-left: auto;\n        margin-right: auto;\n    }\n\n    /* Diseño dividido (Texto a un lado, Caja al otro) */\n    .ishield-split-layout {\n        display: flex;\n        flex-wrap: wrap;\n        gap: 50px;\n        align-items: center;\n        margin-bottom: 60px;\n    }\n\n    .ishield-about-text {\n        flex: 1 1 400px;\n    }\n\n    .ishield-about-text h2 {\n        color: #bf0000;\n        font-size: 2.2em;\n        margin-bottom: 20px;\n        text-transform: uppercase;\n        font-weight: 800;\n        line-height: 1.1;\n    }\n\n    .ishield-about-text p {\n        font-size: 1.1em;\n        line-height: 1.7;\n        margin-bottom: 15px;\n        color: #444;\n    }\n\n    /* Caja de ventajas destacada */\n    .ishield-advantages {\n        flex: 1 1 350px;\n        background-color: #f9f9f9;\n        padding: 40px 30px;\n        border-radius: 12px;\n        border-bottom: 5px solid #bf0000;\n        box-shadow: 0 10px 30px rgba(0,0,0,0.08);\n    }\n\n    .ishield-advantages h3 {\n        margin-top: 0;\n        color: #1a1a1a;\n        font-size: 1.4em;\n        margin-bottom: 25px;\n        text-transform: uppercase;\n    }\n\n    .ishield-advantages ul {\n        list-style: none;\n        padding: 0;\n        margin: 0;\n    }\n\n    .ishield-advantages li {\n        display: flex;\n        align-items: center;\n        margin-bottom: 20px;\n        font-size: 1.05em;\n        font-weight: 600;\n        color: #333;\n    }\n\n    .ishield-advantages li::before {\n        content: \'✓\';\n        color: #fff;\n        background-color: #bf0000;\n        width: 28px;\n        height: 28px;\n        display: inline-flex;\n        justify-content: center;\n        align-items: center;\n        border-radius: 50%;\n        margin-right: 15px;\n        font-size: 16px;\n        flex-shrink: 0;\n    }\n\n    /* Pie de la sección (Botones y Redes) */\n    .ishield-home-footer {\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n        flex-wrap: wrap;\n        gap: 30px;\n        padding-top: 40px;\n        border-top: 1px solid #e0e0e0;\n    }\n\n    /* Grupo de Botones */\n    .ishield-btn-group {\n        display: flex;\n        gap: 15px;\n        flex-wrap: wrap;\n        align-items: center;\n    }\n\n    .ishield-btn-primary {\n        background-color: #bf0000;\n        color: #fff !important;\n        padding: 14px 32px;\n        text-decoration: none;\n        font-weight: bold;\n        text-transform: uppercase;\n        border-radius: 6px;\n        letter-spacing: 1px;\n        transition: all 0.3s ease;\n        text-align: center;\n    }\n\n    .ishield-btn-primary:hover {\n        background-color: #1a1a1a;\n        transform: translateY(-2px);\n    }\n\n    .ishield-btn-secondary {\n        background-color: transparent;\n        color: #1a1a1a !important;\n        padding: 12px 30px;\n        border: 2px solid #1a1a1a;\n        text-decoration: none;\n        font-weight: bold;\n        text-transform: uppercase;\n        border-radius: 6px;\n        letter-spacing: 1px;\n        transition: all 0.3s ease;\n        text-align: center;\n    }\n\n    .ishield-btn-secondary:hover {\n        background-color: #1a1a1a;\n        color: #fff !important;\n        transform: translateY(-2px);\n    }\n\n    /* Redes sociales */\n    .ishield-socials-group {\n        display: flex;\n        gap: 15px;\n    }\n\n    .ishield-socials-group a {\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        width: 48px;\n        height: 48px;\n        border-radius: 50%;\n        background-color: #f1f1f1;\n        color: #333;\n        transition: all 0.3s ease;\n    }\n\n    .ishield-socials-group a svg {\n        width: 22px;\n        height: 22px;\n        fill: currentColor;\n    }\n\n    .ishield-socials-group a:hover {\n        color: #fff;\n        transform: translateY(-4px);\n    }\n\n    .ishield-socials-group a.mail:hover { background-color: #333; }\n    .ishield-socials-group a.ig:hover { background-color: #E1306C; }\n    .ishield-socials-group a.yt:hover { background-color: #FF0000; }\n\n    /* Estilo Hack The Box para el pie legal */\n    .ishield-htb-footer {\n        width: 100%;\n        text-align: center;\n        margin-top: 40px;\n        font-size: 13px; /* Letra pequeña y discreta */\n        color: #6b7280;  /* Gris apagado estilo HTB */\n        line-height: 1.6;\n    }\n\n    .ishield-htb-footer p {\n        margin: 0;\n    }\n\n    .ishield-legal-link {\n        color: #6b7280;\n        text-decoration: underline; /* Subrayado sutil */\n        transition: color 0.3s ease;\n    }\n\n    .ishield-legal-link:hover {\n        color: #bf0000; /* Rojo corporativo al pasar el ratón */\n    }\n\n    /* Adaptación a móviles */\n    @media (max-width: 768px) {\n        .ishield-home-footer {\n            flex-direction: column;\n            justify-content: center;\n            text-align: center;\n        }\n        .ishield-btn-group {\n            justify-content: center;\n            width: 100%;\n        }\n        .ishield-btn-primary, .ishield-btn-secondary {\n            width: 100%;\n            box-sizing: border-box;\n        }\n    }\n</style>\n\n<div class=\"ishield-hero-section\">\n\n    <div class=\"ishield-intro-text\">\n        <p><strong>Auditorías completas, protección web y respuesta inmediata para pymes y negocios online.</strong><br>\n        Identificamos los riesgos de tu infraestructura antes de que sean explotados. Reduce tus vulnerabilidades y opera con total tranquilidad.</p>\n    </div>\n\n    <div class=\"ishield-split-layout\">\n        \n        <div class=\"ishield-about-text\">\n            <h2>Blindamos tu <br>Seguridad</h2>\n            <p><strong>iSHIELD</strong> es tu socio estratégico en ciberseguridad corporativa. Nuestro objetivo es claro: evaluar el nivel de exposición de tus sistemas mediante la simulación de ataques controlados.</p>\n            <p>Comprobamos la eficacia real de tus medidas de protección actuales, aislamos las brechas y te proporcionamos las soluciones técnicas necesarias para mantener tu información a salvo.</p>\n        </div>\n\n        <div class=\"ishield-advantages\">\n            <h3>¿Por qué elegirnos?</h3>\n            <ul>\n                <li>Independencia y objetividad total</li>\n                <li>Más de 25 años de experiencia</li>\n                <li>Simulación de ataques reales</li>\n                <li>Estrategias 100% personalizadas</li>\n            </ul>\n        </div>\n\n    </div>\n\n    <div class=\"ishield-home-footer\">\n        \n        <div class=\"ishield-btn-group\">\n            <a href=\"/contacto\" class=\"ishield-btn-primary\">Solicitar Auditoría</a>\n            <a href=\"/servicios\" class=\"ishield-btn-secondary\">Ver Servicios</a>\n        </div>\n\n        <div class=\"ishield-socials-group\">\n            <a href=\"mailto:ishield@info.com\" class=\"mail\" title=\"Email: ishield@info.com\">\n                <svg viewBox=\"0 0 24 24\"><path d=\"M20 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 4l-8 5-8-5V6l8 5 8-5v2z\"/></svg>\n            </a>\n            <a href=\"https://instagram.com/ishield\" target=\"_blank\" class=\"ig\" title=\"Instagram: @ishield\">\n                <svg viewBox=\"0 0 24 24\"><path d=\"M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zM12 0C8.741 0 8.333.014 7.053.072 2.695.272.273 2.69.073 7.052.014 8.333 0 8.741 0 12c0 3.259.014 3.668.072 4.948.20 4.358 2.618 6.78 6.98 6.98C8.333 23.986 8.741 24 12 24c3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98C15.668.014 15.259 0 12 0zm0 5.838a6.162 6.162 0 100 12.324 6.162 6.162 0 000-12.324zM12 16a4 4 0 110-8 4 4 0 010 8zm6.406-11.845a1.44 1.44 0 100 2.881 1.44 1.44 0 000-2.881z\"/></svg>\n            </a>\n            <a href=\"https://youtube.com/ishield.com\" target=\"_blank\" class=\"yt\" title=\"YouTube: iSHIELD\">\n                <svg viewBox=\"0 0 24 24\"><path d=\"M21.582 6.186a2.684 2.684 0 00-1.884-1.897C18.036 3.84 12 3.84 12 3.84s-6.036 0-7.698.449a2.684 2.684 0 00-1.884 1.897c-.451 1.696-.451 5.234-.451 5.234s0 3.538.451 5.234a2.685 2.685 0 001.884 1.897c1.662.449 7.698.449 7.698.449s6.036 0 7.698-.449a2.685 2.685 0 001.884-1.897c.451-1.696.451-5.234.451-5.234s0-3.538-.451-5.234zM9.6 15.516V8.484L15.6 12l-6 3.516z\"/></svg>\n            </a>\n        </div>\n\n    </div>\n\n    <div class=\"ishield-htb-footer\">\n        <p>Copyright © 2026 <a href=\"/copyright\" class=\"ishield-legal-link\" style=\"text-decoration: none;\">iSHIELD</a>.</p>\n        <p>Todos los derechos reservados. <a href=\"/sla-nivel-de-servicio\" class=\"ishield-legal-link\">Acuerdo de Nivel de Servicio</a>, <a href=\"/politica-de-privacidad\" class=\"ishield-legal-link\">Política de Privacidad</a></p>\n    </div>\n\n</div>\n<!-- /wp:html -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Inicio','','publish','closed','closed','','inicio','','','2026-03-11 12:37:17','2026-03-11 11:37:17','',0,'http://ishield-2.local/?page_id=7',0,'page','',0);
