INSERT INTO `wp_posts` VALUES (11,1,'2026-01-21 11:37:48','2026-01-21 10:37:48','<!-- wp:paragraph {\"className\":\"is-style-text-subtitle\",\"style\":{\"color\":{\"text\":\"#b42e2e\"}},\"backgroundColor\":\"base\"} -->\n<p class=\"is-style-text-subtitle has-base-background-color has-text-color has-background\" style=\"color:#b42e2e\"><strong>Protección digital a medida para tu empresa</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary><strong>¿Qué es iSHIELD?</strong></summary><!-- wp:paragraph {\"placeholder\":\"Teclea / para añadir un bloque oculto\"} -->\n<p>Empresa de ciberseguridad con más de 25 años dedicada a proteger la infraestructura digital de empresas y pymes. Prevención de vulnerabilidades, detección temprana y respuesta eficaz.</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary><strong>Servicios</strong></summary><!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Auditorías de seguridad y análisis de vulnerabilidades</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Consultoría estratégica y cumplimiento normativo</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Gestión y respuesta ante incidentes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Monitorización 24/7</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Planes de continuidad y recuperación</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Formación y concienciación</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></details>\n<!-- /wp:details -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary>¿Por qué elegirnos?</summary><!-- wp:paragraph {\"placeholder\":\"Teclea / para añadir un bloque oculto\"} -->\n<p>Independencia total<br>Más de 25 años de experiencia<br>Estrategias personalizadas</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"verticalAlignment\":\"top\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">Contacto</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:social-links {\"align\":\"center\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\",\"justifyContent\":\"center\"}} -->\n<ul class=\"wp-block-social-links aligncenter\"><!-- wp:social-link {\"service\":\"mail\"} /-->\n\n<!-- wp:social-link {\"url\":\"\",\"service\":\"instagram\"} /-->\n\n<!-- wp:social-link {\"service\":\"youtube\"} /-->\n\n<!-- wp:social-link {\"service\":\"x\"} /--></ul>\n<!-- /wp:social-links --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','ISHIELD','','inherit','closed','closed','','7-revision-v1','','','2026-01-21 11:37:48','2026-01-21 10:37:48','',7,'http://ishield-2.local/?p=11',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (13,1,'2026-02-11 10:13:59','2026-02-11 09:13:59','<!-- wp:paragraph {\"align\":\"center\",\"className\":\"is-style-text-subtitle\",\"style\":{\"color\":{\"text\":\"#b42e2e\"}},\"backgroundColor\":\"base\"} -->\n<p class=\"has-text-align-center is-style-text-subtitle has-base-background-color has-text-color has-background\" style=\"color:#b42e2e\"><strong>Protegemos tu empresa de ciberataques las 24h</strong></p>\n<!-- /wp:paragraph -->\n\n<p style=\"font-size: 1.2em; color: #666; margin-bottom: 40px; max-width: 600px; margin-left: auto; margin-right: auto;\">Auditorías completas, protección web y respuesta inmediata para pymes y negocios online. Reduce vulnerabilidades    ahora.</p>\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary><strong>¿Qué es iSHIELD?</strong></summary><!-- wp:paragraph {\"placeholder\":\"Teclea / para añadir un bloque oculto\"} -->\n<p>Empresa de ciberseguridad con más de 25 años dedicada a proteger la infraestructura digital de empresas y pymes. Prevención de vulnerabilidades, detección temprana y respuesta eficaz.</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary><strong>Servicios</strong></summary><!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Auditorías de seguridad y análisis de vulnerabilidades</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Consultoría estratégica y cumplimiento normativo</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Gestión y respuesta ante incidentes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Monitorización 24/7</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Planes de continuidad y recuperación</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Formación y concienciación</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></details>\n<!-- /wp:details -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:details -->\n<details class=\"wp-block-details\"><summary>¿Por qué elegirnos?</summary><!-- wp:paragraph {\"placeholder\":\"Teclea / para añadir un bloque oculto\"} -->\n<p>Independencia total<br>Más de 25 años de experiencia<br>Estrategias personalizadas</p>\n<!-- /wp:paragraph --></details>\n<!-- /wp:details -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"verticalAlignment\":\"top\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">Contacto</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:social-links {\"align\":\"center\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\",\"justifyContent\":\"center\"}} -->\n<ul class=\"wp-block-social-links aligncenter\"><!-- wp:social-link {\"service\":\"mail\"} /-->\n\n<!-- wp:social-link {\"url\":\"\",\"service\":\"instagram\"} /-->\n\n<!-- wp:social-link {\"service\":\"youtube\"} /-->\n\n<!-- wp:social-link {\"service\":\"x\"} /--></ul>\n<!-- /wp:social-links --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','iSHIELD','','inherit','closed','closed','','7-revision-v1','','','2026-02-11 10:13:59','2026-02-11 09:13:59','',7,'http://ishield-2.local/?p=13',0,'revision','',0);
