 wp:columns {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-columns are-vertically-aligned-center\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:buttons {\"layout\":{\"type\":\"flex\",\"verticalAlignment\":\"top\"}} -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">Contacto</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:social-links {\"align\":\"center\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\",\"justifyContent\":\"center\"}} -->\n<ul class=\"wp-block-social-links aligncenter\"><!-- wp:social-link {\"url\":\"ishield@info.com\",\"service\":\"mail\"} /-->\n\n<!-- wp:social-link {\"url\":\"@ishield\",\"service\":\"instagram\"} /-->\n\n<!-- wp:social-link {\"url\":\"youtube/ishield.com\",\"service\":\"youtube\"} /--></ul>\n<!-- /wp:social-links --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','iSHIELD','','inherit','closed','closed','','7-revision-v1','','','2026-02-11 10:24:22','2026-02-11 09:24:22','',7,'http://ishield-2.local/?p=16',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (17,1,'2026-03-04 10:25:53','2026-03-04 09:25:53','<!-- wp:html -->\n<style>\n    /* Contenedor principal ajustado */\n    .ishield-container {\n        font-family: \'Montserrat\', sans-serif;\n        color: #333;\n        width: 100%;\n        max-width: 100%;\n        box-sizing: border-box;\n        display: flex;\n        flex-wrap: wrap;\n        gap: 30px;\n        padding: 10px;\n        background-color: #fff;\n    }\n    \n    .ishield-info, .ishield-form {\n        flex: 1;\n        min-width: 280px;\n    }\n\n    /* Títulos */\n    .ishield-title {\n        color: #bf0000;\n        border-bottom: 2px solid #bf0000;\n        padding-bottom: 8px;\n        margin-bottom: 15px;\n        text-transform: uppercase;\n        font-weight: bold;\n        font-size: 1.2em;\n    }\n\n    /* Cajas de información */\n    .info-box {\n        display: flex;\n        align-items: center;\n        margin-bottom: 15px;\n        background: #f9f9f9;\n        padding: 12px;\n        border-left: 4px solid #bf0000;\n        border-radius: 0 4px 4px 0;\n    }\n    \n    .info-box i {\n        font-size: 20px;\n        color: #bf0000;\n        margin-right: 12px;\n        width: 25px;\n        text-align: center;\n    }\n\n    .info-box p, .info-box div {\n        margin: 0;\n        font-size: 14px;\n        line-height: 1.4;\n    }\n\n    .info-box a {\n        color: #333;\n        text-decoration: none;\n        font-weight: 600;\n    }\n\n    /* Estilos del Formulario */\n    .wpcf7-form label {\n        display: block;\n        margin-bottom: 4px;\n        font-weight: bold;\n        font-size: 13px;\n        margin-top: 10px;\n    }\n\n    .wpcf7-form input[type=\"text\"],\n    .wpcf7-form input[type=\"email\"],\n    .wpcf7-form select,\n    .wpcf7-form textarea {\n        width: 100%;\n        box-sizing: border-box;\n        padding: 8px;\n        border: 1px solid #ccc;\n        border-radius: 4px;\n        font-family: inherit;\n    }\n\n    .wpcf7-form input[type=\"submit\"] {\n        background-color: #bf0000;\n        color: white;\n        border: none;\n        padding: 12px 25px;\n        text-transform: uppercase;\n        font-weight: bold;\n        cursor: pointer;\n        width: 100%;\n        border-radius: 4px;\n        margin-top: 15px;\n    }\n\n    .wpcf7-form input[type=\"submit\"]:hover {\n        background-color: #900000;\n    }\n\n    /* Pie de página limpio */\n    .ishield-footer-note {\n        width: 100%;\n        text-align: center;\n        font-size: 11px;\n        color: #888;\n        margin-top: 20px;\n        border-top: 1px solid #eee;\n        padding-top: 15px;\n    }\n</style>\n\n<div class=\"ishield-container\">\n\n    <div class=\"ishield-info\">\n        <h3 class=\"ishield-title\">Contacto</h3>\n\n        <p style=\"margin-bottom: 20px;\">\n            Ponte en contacto con el equipo de <strong>iSHIELD</strong> para asegurar tu infraestructura.\n        </p>\n\n        <div class=\"info-box\">\n            <i>✉️</i>\n            <div>\n                <strong>Departamento General:</strong><br>\n                <a href=\"mailto:info@ishield.es\">info@ishield.es</a>\n            </div>\n        </div>\n\n        <div class=\"info-box\">\n            <i>🛠️</i>\n            <div>\n                <strong>Soporte Técnico:</strong><br>\n                <a href=\"mailto:soporte@ishield.es\">soporte@ishield.es</a>\n            </div>\n        </div>\n\n        <p style=\"font-size: 0.9em; margin-top: 20px; color: #555;\">\n            Auditamos y protegemos tus sistemas contra vulnerabilidades críticas.\n        </p>\n    </div>\n\n    <div class=\"ishield-form\">\n        <h3 class=\"ishield-title\">Solicita tu Auditoría</h3>\n\n        <form action=\"\" method=\"post\" class=\"wpcf7-form\">\n            <label>Nombre o Empresa</label>\n            <input type=\"text\" name=\"your-name\" value=\"\" aria-required=\"true\">\n\n            <label>Correo electrónico (requerido)</label>\n            <input type=\"email\" name=\"your-email\" value=\"\" aria-required=\"true\">\n\n            <label>Servicio de Interés</label>\n            <select name=\"your-service\">\n                <option value=\"Auditoría de Vulnerabilidades\">Auditoría de Vulnerabilidades</option>\n                <option value=\"Pentesting\">Pentesting</option>\n                <option value=\"Seguridad Servidores\">Seguridad Servidores</option>\n            </select>\n\n            <label>Mensaje / Detalles de la infraestructura</label>\n            <textarea name=\"your-message\" cols=\"40\" rows=\"4\"></textarea>\n\n            <input type=\"submit\" value=\"Enviar Solicitud\">\n        </form>\n        <div style=\"margin-top: 15px; font-size: 11px; color: #777;\">\n            <p>Tus datos serán tratados con confidencialidad bajo la normativa vigente para proteger tu información sensible ante ataques.</p>\n        </div>\n    </div>\n\n    <div class=\"ishield-footer-note\">\n        <p><strong>SHIELD - La mejor seguridad, los mejores resultados</strong></p>\n        <p>Proyecto Intermodular 2º SMR - CESUR</p>\n    </div>\n\n</div>\n<!-- /wp:html -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Contacto','','publish','closed','closed','','contacto','','','2026-03-04 10:25:53','2026-03-04 09:25:53','',0,'https://wealthy-decision.localsite.io/?page_id=17',0,'page','',0);
INSERT INTO `wp_posts` VALUES (18,1,'2026-02-11 10:40:43','2026-02-11 09:40:43','<!-- wp:paragraph -->\n<p>Te damos la bienvenida a WordPress. Esta es tu primera entrada. Edítala o bórrala, ¡luego empieza a escribir!</p>\n<!-- /wp:paragraph -->','¡Hola, mundo!','','inherit','closed','closed','','1-revision-v1','','','2026-02-11 10:40:43','2026-02-11 09:40:43','',1,'http://ishield-2.local/?p=18',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (20,1,'2026-03-04 10:26:05','2026-03-04 09:26:05','<!-- wp:html -->\n<style>\n    /* Contenedor principal ajustado */\n    .ishield-container {\n        font-family: \'Montserrat\', sans-serif;\n        color: #333;\n        width: 100%;\n        max-width: 1200px;\n        margin: 0 auto;\n        box-sizing: border-box;\n        display: flex;\n        flex-wrap: wrap;\n        gap: 20px;\n        padding: 10px;\n        background-color: #fff;\n    }\n\n    /* Título de la sección */\n    .ishield-section-header {\n        width: 100%;\n        margin-bottom: 20px;\n    }\n\n    .ishield-title {\n        color: #bf0000;\n        border-bottom: 2px solid #bf0000;\n        padding-bottom: 8px;\n        margin-bottom: 10px;\n        text-transform: uppercase;\n        font-weight: bold;\n        font-size: 1.5em;\n        display: inline-block;\n    }\n\n    .ishield-subtitle {\n        font-size: 1em;\n        color: #555;\n        margin-bottom: 30px;\n    }\n\n    /* Cuadrícula de servicios */\n    .services-grid {\n        display: flex;\n        flex-wrap: wrap;\n        gap: 30px;\n        width: 100%;\n    }\n\n    /* Tarjetas de cada servicio */\n    .service-card {\n        background: #f9f9f9;\n        border-left: 4px solid #bf0000;\n        border-radius: 0 6px 6px 0;\n        padding: 25px;\n        flex: 1 1 calc(50% - 30px); /* 2 columnas en PC */\n        min-width: 280px; /* 1 columna en móviles */\n        box-sizing: border-box;\n        transition: transform 0.3s ease, box-shadow 0.3s ease;\n    }\n\n    .service-card:hover {\n        transform: translateY(-5px);\n        box-shadow: 0 8px 15px rgba(0,0,0,0.05);\n    }\n\n    .service-icon {\n        font-size: 35px;\n        margin-bottom: 15px;\n        color: #bf0000;\n    }\n\n    .service-name {\n        color: #bf0000;\n        font-size: 1.2em;\n        font-weight: bold;\n        margin-bottom: 10px;\n        text-transform: uppercase;\n    }\n\n    .service-desc {\n        font-size: 14px;\n        line-height: 1.6;\n        color: #444;\n        margin: 0;\n    }\n\n    /* Llamada a la acción (CTA) */\n    .ishield-cta {\n        width: 100%;\n        text-align: center;\n        margin-top: 40px;\n        padding: 40px 20px;\n        background-color: #f9f9f9;\n        border-top: 2px solid #eee;\n        border-radius: 8px;\n        box-sizing: border-box;\n    }\n\n    .ishield-cta h3 {\n        color: #333;\n        margin-bottom: 15px;\n    }\n\n    .ishield-btn {\n        background-color: #bf0000;\n        color: white !important;\n        text-decoration: none;\n        padding: 12px 30px;\n        font-weight: bold;\n        text-transform: uppercase;\n        border-radius: 4px;\n        display: inline-block;\n        transition: background 0.3s;\n        margin-top: 10px;\n    }\n\n    .ishield-btn:hover {\n        background-color: #900000;\n    }\n\n</style>\n\n<div class=\"ishield-container\">\n\n    <div class=\"ishield-section-header\">\n        <h2 class=\"ishield-title\">Nuestros Servicios</h2>\n        <p class=\"ishield-subtitle\">Soluciones avanzadas para proteger la información sensible de tu empresa ante cualquier amenaza cibernética.</p>\n    </div>\n\n    <div class=\"services-grid\">\n\n        <div class=\"service-card\">\n            <div class=\"service-icon\">🛡️</div>\n            <div class=\"service-name\">Auditoría de Ciberseguridad</div>\n            <p class=\"service-desc\">\n                Evaluamos el nivel de exposición de tus sistemas informáticos a posibles ataques. Identificamos riesgos, brechas de seguridad y elaboramos un informe detallado con recomendaciones prioritarias para mitigar cualquier debilidad en tu infraestructura.\n            </p>\n        </div>\n\n        <div class=\"service-card\">\n            <div class=\"service-icon\">🎯</div>\n            <div class=\"service-name\">Pentesting y Hacking Ético</div>\n            <p class=\"service-desc\">\n                Simulamos escenarios de ataque controlados utilizando entornos y herramientas profesionales (Kali Linux, Nmap, Metasploit). Explotamos de forma segura las vulnerabilidades detectadas para comprobar la eficacia real de tus medidas de protección actuales.\n            </p>\n        </div>\n\n        <div class=\"service-card\">\n            <div class=\"service-icon\">🖥️</div>\n            <div class=\"service-name\">Securización de Servidores</div>\n            <p class=\"service-desc\">\n                Desplegamos, configuramos y endurecemos la seguridad de tus servidores (Windows Server 2019 / Linux). Implementamos políticas restrictivas en Active Directory, enrutamiento seguro y gestión de servicios (DNS, DHCP) aislando tu red de accesos no autorizados.\n            </p>\n        </div>\n\n        <div class=\"service-card\">\n            <div class=\"service-icon\">🌐</div>\n            <div class=\"service-name\">Protección Web y Anti-Malware</div>\n            <p class=\"service-desc\">\n                Evita filtraciones, manipulaciones o robos de datos que puedan generar daños reputacionales. Ofrecemos protección en tiempo real para tu sitio web y red local contra la inyección de código, robo de credenciales y todo tipo de software malicioso.\n            </p>\n        </div>\n\n    </div>\n\n    <div class=\"ishield-cta\">\n        <h3>¿Listo para blindar la infraestructura de tu empresa?</h3>\n        <p style=\"color: #666; margin-bottom: 20px;\">Sin las medidas adecuadas, tu información está expuesta. Nuestro equipo de expertos está listo para ayudarte.</p>\n        <a href=\"/contacto\" class=\"ishield-btn\">Solicitar Auditoría</a>\n    </div>\n\n</div>\n<!-- /wp:html -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Servicios','','publish','closed','closed','','servicios','','','2026-03-08 12:18:02','2026-03-08 11:18:02','',0,'http://ishield-2.local/?page_id=20',0,'page','',0);
