INSERT INTO `wp_posts` VALUES (27,1,'2026-02-11 10:56:32','2026-02-11 09:56:32','<!-- wp:html -->\n<style>\n    /* Contenedor principal ajustado */\n    .ishield-container {\n        font-family: \'Montserrat\', sans-serif;\n        color: #333;\n        width: 100%;\n        max-width: 100%;\n        box-sizing: border-box;\n        display: flex;\n        flex-wrap: wrap;\n        gap: 30px;\n        padding: 10px;\n        background-color: #fff;\n    }\n    \n    .ishield-info, .ishield-form {\n        flex: 1;\n        min-width: 280px;\n    }\n\n    /* Títulos */\n    .ishield-title {\n        color: #bf0000;\n        border-bottom: 2px solid #bf0000;\n        padding-bottom: 8px;\n        margin-bottom: 15px;\n        text-transform: uppercase;\n        font-weight: bold;\n        font-size: 1.2em;\n    }\n\n    /* Cajas de información */\n    .info-box {\n        display: flex;\n        align-items: center;\n        margin-bottom: 15px;\n        background: #f9f9f9;\n        padding: 12px;\n        border-left: 4px solid #bf0000;\n        border-radius: 0 4px 4px 0;\n    }\n    \n    .info-box i {\n        font-size: 20px;\n        color: #bf0000;\n        margin-right: 12px;\n        width: 25px;\n        text-align: center;\n    }\n\n    .info-box p, .info-box div {\n        margin: 0;\n        font-size: 14px;\n        line-height: 1.4;\n    }\n\n    .info-box a {\n        color: #333;\n        text-decoration: none;\n        font-weight: 600;\n    }\n\n    /* Estilos del Formulario */\n    .wpcf7-form label {\n        display: block;\n        margin-bottom: 4px;\n        font-weight: bold;\n        font-size: 13px;\n        margin-top: 10px;\n    }\n\n    .wpcf7-form input[type=\"text\"],\n    .wpcf7-form input[type=\"email\"],\n    .wpcf7-form select,\n    .wpcf7-form textarea {\n        width: 100%;\n        box-sizing: border-box;\n        padding: 8px;\n        border: 1px solid #ccc;\n        border-radius: 4px;\n        font-family: inherit;\n    }\n\n    .wpcf7-form input[type=\"submit\"] {\n        background-color: #bf0000;\n        color: white;\n        border: none;\n        padding: 12px 25px;\n        text-transform: uppercase;\n        font-weight: bold;\n        cursor: pointer;\n        width: 100%;\n        border-radius: 4px;\n        margin-top: 15px;\n    }\n\n    .wpcf7-form input[type=\"submit\"]:hover {\n        background-color: #900000;\n    }\n\n    /* Pie de página limpio */\n    .ishield-footer-note {\n        width: 100%;\n        text-align: center;\n        font-size: 11px;\n        color: #888;\n        margin-top: 20px;\n        border-top: 1px solid #eee;\n        padding-top: 15px;\n    }\n</style>\n\n<div class=\"ishield-container\">\n\n    <div class=\"ishield-info\">\n        <h3 class=\"ishield-title\">Contacto</h3>\n\n        <p style=\"margin-bottom: 20px;\">\n            Ponte en contacto con el equipo de <strong>iSHIELD</strong> para asegurar tu infraestructura.\n        </p>\n\n        <div class=\"info-box\">\n            <i>✉️</i>\n            <div>\n                <strong>Departamento General:</strong><br>\n                <a href=\"mailto:info@ishield.es\">info@ishield.es</a>\n            </div>\n        </div>\n\n        <div class=\"info-box\">\n            <i>🛠️</i>\n            <div>\n                <strong>Soporte Técnico:</strong><br>\n                <a href=\"mailto:soporte@ishield.es\">soporte@ishield.es</a>\n            </div>\n        </div>\n\n        <p style=\"font-size: 0.9em; margin-top: 20px; color: #555;\">\n            Auditamos y protegemos tus sistemas contra vulnerabilidades críticas.\n        </p>\n    </div>\n\n    <div class=\"ishield-form\">\n        <h3 class=\"ishield-title\">Solicita tu Auditoría</h3>\n\n        <form action=\"\" method=\"post\" class=\"wpcf7-form\">\n            <label>Nombre o Empresa</label>\n            <input type=\"text\" name=\"your-name\" value=\"\" aria-required=\"true\">\n\n            <label>Correo electrónico (requerido)</label>\n            <input type=\"email\" name=\"your-email\" value=\"\" aria-required=\"true\">\n\n            <label>Servicio de Interés</label>\n            <select name=\"your-service\">\n                <option value=\"Auditoría de Vulnerabilidades\">Auditoría de Vulnerabilidades</option>\n                <option value=\"Pentesting\">Pentesting</option>\n                <option value=\"Seguridad Servidores\">Seguridad Servidores</option>\n            </select>\n\n            <label>Mensaje / Detalles de la infraestructura</label>\n            <textarea name=\"your-message\" cols=\"40\" rows=\"4\"></textarea>\n\n            <input type=\"submit\" value=\"Enviar Solicitud\">\n        </form>\n        <div style=\"margin-top: 15px; font-size: 11px; color: #777;\">\n            <p>Tus datos serán tratados con confidencialidad bajo la normativa vigente para proteger tu información sensible ante ataques.</p>\n        </div>\n    </div>\n\n    <div class=\"ishield-footer-note\">\n        <p><strong>SHIELD - La mejor seguridad, los mejores resultados</strong></p>\n        <p>Proyecto Intermodular 2º SMR - CESUR</p>\n    </div>\n\n</div>\n<!-- /wp:html -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Contacto','','inherit','closed','closed','','17-revision-v1','','','2026-02-11 10:56:32','2026-02-11 09:56:32','',17,'https://wealthy-decision.localsite.io/?p=27',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (29,1,'2026-03-04 10:27:32','2026-03-04 09:27:32','<!-- wp:template-part {\"slug\":\"header\",\"theme\":\"twentytwentyfive\"} /-->\n\n<!-- wp:group {\"tagName\":\"main\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"var:preset|spacing|60\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<main class=\"wp-block-group\" style=\"margin-top:var(--wp--preset--spacing--60)\"><!-- wp:group {\"align\":\"full\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"var:preset|spacing|60\",\"bottom\":\"var:preset|spacing|60\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull\" style=\"padding-top:var(--wp--preset--spacing--60);padding-bottom:var(--wp--preset--spacing--60)\"><!-- wp:post-title {\"textAlign\":\"center\",\"level\":1,\"style\":{\"spacing\":{\"margin\":{\"bottom\":\"var:preset|spacing|60\"}}},\"fontSize\":\"x-large\"} /-->\n\n<!-- wp:post-featured-image {\"style\":{\"spacing\":{\"margin\":{\"bottom\":\"var:preset|spacing|60\"}}}} /-->\n\n<!-- wp:post-content {\"align\":\"full\",\"layout\":{\"type\":\"constrained\"}} /--></div>\n<!-- /wp:group --></main>\n<!-- /wp:group -->','Páginas','Muestra una página estática, a menos que se le haya aplicado una plantilla personalizada o exista una plantilla dedicada.','publish','closed','closed','','page','','','2026-03-09 13:19:09','2026-03-09 12:19:09','',0,'http://ishield-2.local/page/',0,'wp_template','',0);
