INSERT INTO `wp_posts` VALUES (54,1,'2026-03-09 13:15:40','2026-03-09 12:15:40','<!-- wp:navigation-link {\"label\":\"Inicio\",\"type\":\"page\",\"id\":7,\"url\":\"http://ishield-2.local/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Servicios\",\"type\":\"page\",\"id\":20,\"url\":\"http://ishield-2.local/servicios/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Contacto\",\"type\":\"page\",\"id\":17,\"url\":\"http://ishield-2.local/contacto/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->','Navegación (copia)','','publish','closed','closed','','navegacion-copia','','','2026-03-09 13:19:09','2026-03-09 12:19:09','',0,'http://ishield-2.local/navegacion-copia/',0,'wp_navigation','',0);
