efore {\n        content: \'✓\';\n        color: #fff;\n        background-color: #bf0000;\n        width: 28px;\n        height: 28px;\n        display: inline-flex;\n        justify-content: center;\n        align-items: center;\n        border-radius: 50%;\n        margin-right: 15px;\n        font-size: 16px;\n        flex-shrink: 0;\n    }\n\n    /* Pie de la sección (Botones y Redes) */\n    .ishield-home-footer {\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n        flex-wrap: wrap;\n        gap: 30px;\n        padding-top: 40px;\n        border-top: 1px solid #e0e0e0;\n    }\n\n    /* Grupo de Botones */\n    .ishield-btn-group {\n        display: flex;\n        gap: 15px;\n        flex-wrap: wrap;\n        align-items: center;\n    }\n\n    .ishield-btn-primary {\n        background-color: #bf0000;\n        color: #fff !important;\n        padding: 14px 32px;\n        text-decoration: none;\n        font-weight: bold;\n        text-transform: uppercase;\n        border-radius: 6px;\n        letter-spacing: 1px;\n        transition: all 0.3s ease;\n        text-align: center;\n    }\n\n    .ishield-btn-primary:hover {\n        background-color: #1a1a1a;\n        transform: translateY(-2px);\n    }\n\n    .ishield-btn-secondary {\n        background-color: transparent;\n        color: #1a1a1a !important;\n        padding: 12px 30px;\n        border: 2px solid #1a1a1a;\n        text-decoration: none;\n        font-weight: bold;\n        text-transform: uppercase;\n        border-radius: 6px;\n        letter-spacing: 1px;\n        transition: all 0.3s ease;\n        text-align: center;\n    }\n\n    .ishield-btn-secondary:hover {\n        background-color: #1a1a1a;\n        color: #fff !important;\n        transform: translateY(-2px);\n    }\n\n    /* Redes sociales */\n    .ishield-socials-group {\n        display: flex;\n        gap: 15px;\n    }\n\n    .ishield-socials-group a {\n        display: flex;\n     